/// Projector that updates Workflow projection from events
pub struct WorkflowProjector<R: WorkflowProjectionRepository> {
    repository: Arc<R>,
}

impl<R: WorkflowProjectionRepository> WorkflowProjector<R> {
    /// Create a new projector
    pub fn new(repository: Arc<R>) -> Self {
        Self { repository }
    }

    /// Rebuild all projections from event history
    pub async fn rebuild(&self) -> Result<u64> {
        self.repository.rebuild_all().await
    }

    /// Process a stored event from the event store
    ///
    /// This method dispatches the event to the appropriate handler based on event type.
    /// Returns Ok(true) if the event was processed, Ok(false) if it was skipped.
    pub async fn process_stored_event(&self, event: &crate::infrastructure::event_store::StoredEvent) -> Result<bool>
    where
        Self: WorkflowEventHandler,
    {
        let sequence = event.sequence;

        match event.event_type.as_str() {
            "WorkflowCreatedEvent" => {
                let created: WorkflowCreatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_created(created, sequence).await?;
                Ok(true)
            }
            "WorkflowUpdatedEvent" => {
                let updated: WorkflowUpdatedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_updated(updated, sequence).await?;
                Ok(true)
            }
            "WorkflowDeletedEvent" => {
                let deleted: WorkflowDeletedEvent = serde_json::from_value(event.payload.clone())?;
                self.on_deleted(deleted, sequence).await?;
                Ok(true)
            }
            _ => Ok(false), // Event type not handled by this projector
        }
    }
}

#[async_trait]
impl<R: WorkflowProjectionRepository> WorkflowEventHandler for WorkflowProjector<R> {

    async fn on_created(&self, event: WorkflowCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = WorkflowProjection::new(
            event.id,
            event.workflow_type,
            event.status,
            event.initiator_id,
            event.target_user_id,
            event.title,
            event.description,
            event.context,
            event.current_step,
            event.total_steps,
            event.progress_percentage,
            event.started_at,
            event.completed_at,
            event.failed_at,
            event.expires_at,
            event.retry_count,
            event.max_retries,
            event.error_message,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: WorkflowUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.workflow_type = event.workflow_type;
            projection.status = event.status;
            projection.initiator_id = event.initiator_id;
            projection.target_user_id = event.target_user_id;
            projection.title = event.title;
            projection.description = event.description;
            projection.context = event.context;
            projection.current_step = event.current_step;
            projection.total_steps = event.total_steps;
            projection.progress_percentage = event.progress_percentage;
            projection.started_at = event.started_at;
            projection.completed_at = event.completed_at;
            projection.failed_at = event.failed_at;
            projection.expires_at = event.expires_at;
            projection.retry_count = event.retry_count;
            projection.max_retries = event.max_retries;
            projection.error_message = event.error_message;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: WorkflowDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

